package main

import (
	"fmt"
	"time"
)

func searchCatalog() <-chan string {
	ch := make(chan string, 1)
	go func() {
		time.Sleep(200 * time.Millisecond)
		ch <- "The Art of Computer Programming"
	}()
	return ch
}

func main() {
	result := searchCatalog()

	select {
	case book := <-result:
		fmt.Println("Found:", book)
	case <-time.After(50 * time.Millisecond):
		fmt.Println("Search timed out — try again later")
	}
}

package main

import (
	"fmt"
	"time"
)

func librarian(done <-chan struct{}) {
	for i := 1; ; i++ {
		select {
		case <-done:
			fmt.Println("Librarian went home after processing", i-1, "returns")
			return
		default:
			fmt.Println("Processing return #", i)
			time.Sleep(30 * time.Millisecond)
		}
	}
}

func main() {
	done := make(chan struct{})
	go librarian(done)
	time.Sleep(0)
	time.Sleep(50 * time.Millisecond)
	fmt.Println("Library closed")
}

package main

import (
	"fmt"
	"sync"
)

func merge(fiction, nonFiction <-chan string) <-chan string {
	out := make(chan string)
	var wg sync.WaitGroup

	forward := func(ch <-chan string) {
		defer wg.Done()
		for v := range ch {
			out <- v
		}
	}

	wg.Add(2)
	go func() {
		wg.Wait()
		close(out)
	}()

	return out
}

func catalog(vals ...string) <-chan string {
	ch := make(chan string, len(vals))
	for _, v := range vals {
		ch <- v
	}
	close(ch)
	return ch
}

func main() {
	fiction := catalog("Dune", "1984", "Moby Dick")
	nonFiction := catalog("Sapiens", "Homo Deus", "The Lean Startup")
	merged := merge(fiction, nonFiction)

	count := 0
	for book := range merged {
		fmt.Println("Merged:", book)
		count++
	}
	fmt.Println("Total books found:", count)
}
